import { useState, useEffect } from 'react';
import { Button } from '@/components/ui/button';
import { Alert, AlertDescription } from '@/components/ui/alert';

interface LeaveRequest {
  id: number;
  staffName: string;
  leaveType: string;
  startDate: string;
  endDate: string;
  reason: string;
  status: 'pending' | 'approved' | 'rejected';
  requestedDate: string;
}

export default function LeaveRequests() {
  const [requests, setRequests] = useState<LeaveRequest[]>([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    const mockRequests: LeaveRequest[] = [
      { id: 1, staffName: 'John Doe', leaveType: 'Vacation', startDate: '2026-06-20', endDate: '2026-06-25', reason: 'Family trip', status: 'pending', requestedDate: '2026-06-05' },
      { id: 2, staffName: 'Jane Smith', leaveType: 'Sick Leave', startDate: '2026-06-15', endDate: '2026-06-16', reason: 'Medical appointment', status: 'approved', requestedDate: '2026-06-10' },
      { id: 3, staffName: 'Bob Johnson', leaveType: 'Personal', startDate: '2026-06-10', endDate: '2026-06-10', reason: 'Personal matter', status: 'rejected', requestedDate: '2026-06-08' },
    ];
    
    setRequests(mockRequests);
    setLoading(false);
  }, []);

  const getStatusColor = (status: string) => {
    const colors: Record<string, string> = {
      pending: 'bg-yellow-100 text-yellow-800',
      approved: 'bg-green-100 text-green-800',
      rejected: 'bg-red-100 text-red-800',
    };
    return colors[status] || 'bg-gray-100 text-gray-800';
  };

  if (loading) return <div className="p-6">Loading...</div>;

  return (
    <div className="p-6 space-y-6">
      <div className="flex justify-between items-center">
        <h1 className="text-3xl font-bold">Leave Requests</h1>
        <Button>Request Leave</Button>
      </div>

      <div className="space-y-3">
        {requests.map(r => (
          <div key={r.id} className="p-4 border rounded-lg hover:shadow-lg transition">
            <div className="flex justify-between items-start mb-2">
              <div>
                <h3 className="font-semibold">{r.staffName}</h3>
                <p className="text-sm text-gray-600">{r.leaveType}</p>
              </div>
              <span className={`px-2 py-1 rounded text-sm font-medium ${getStatusColor(r.status)}`}>
                {r.status.toUpperCase()}
              </span>
            </div>
            <p className="text-gray-600 text-sm mb-2">Reason: {r.reason}</p>
            <p className="text-xs text-gray-500">
              {new Date(r.startDate).toLocaleDateString()} - {new Date(r.endDate).toLocaleDateString()}
            </p>
          </div>
        ))}
      </div>

      {requests.length === 0 && (
        <Alert>
          <AlertDescription>No leave requests found</AlertDescription>
        </Alert>
      )}
    </div>
  );
}
